@@ -0,0 +1,38 @@
+output "scale_tier" {
+  description = "Scale tier this deployment is sized for."
+  value       = var.scale_tier
+}
+
+output "instance_type" {
+  description = "EC2 instance type used by every backend in this deployment."
+  value       = local.tier.instance_type
+}
+
+output "ami_id" {
+  description = "AMI ID resolved (or pinned)."
+  value       = local.resolved_ami_id
+}
+
+output "endpoints" {
+  description = "Per-backend connection info. Use private_ip from inside the VPC."
+  value = {
+    pgvector = {
+      private_ip = module.pgvector.private_ip
+      public_ip  = module.pgvector.public_ip
+      port       = 5432
+      protocol   = "postgres"
+    }
+    qdrant = {
+      private_ip = module.qdrant.private_ip
+      public_ip  = module.qdrant.public_ip
+      rest_port  = 6333
+      grpc_port  = 6334
+    }
+    weaviate = {
+      private_ip = module.weaviate.private_ip
+      public_ip  = module.weaviate.public_ip
+      rest_port  = 8080
+      grpc_port  = 50051
+    }
+  }
+}

@@ -0,0 +1,51 @@
+variable "scale_tier" {
+  description = "Vector-count scale: \"1m\" | \"10m\" | \"100m\". Drives instance type + EBS sizing per docs/infra.md."
+  type        = string
+
+  validation {
+    condition     = contains(["1m", "10m", "100m"], var.scale_tier)
+    error_message = "scale_tier must be one of: 1m, 10m, 100m."
+  }
+}
+
+variable "region" {
+  description = "AWS region. Single region per D-002."
+  type        = string
+  default     = "us-east-1"
+}
+
+variable "availability_zone" {
+  description = "Single AZ for all instances per D-002."
+  type        = string
+  default     = "us-east-1a"
+}
+
+variable "name_prefix" {
+  description = "Prefix on every resource name (e.g. \"vss-bench\")."
+  type        = string
+  default     = "vss-bench"
+}
+
+variable "ssh_ingress_cidrs" {
+  description = "Operator CIDR(s) allowed SSH ingress (e.g. [\"203.0.113.4/32\"]). Empty disables SSH entirely."
+  type        = list(string)
+  default     = []
+}
+
+variable "key_name" {
+  description = "EC2 key-pair name in the deployment region. Optional."
+  type        = string
+  default     = null
+}
+
+variable "ami_id" {
+  description = "Ubuntu 22.04 LTS AMI ID in the deployment region. The data source below resolves the latest by default; override to pin."
+  type        = string
+  default     = null
+}
+
+variable "tags" {
+  description = "Extra tags layered on top of the per-deploy defaults."
+  type        = map(string)
+  default     = {}
+}

@@ -0,0 +1,12 @@
+terraform {
+  required_version = ">= 1.6.0"
+  required_providers {
+    aws = {
+      source  = "hashicorp/aws"
+      version = ">= 5.40.0"
+    }
+  }
+}
+
+# Local state by default — single operator, ephemeral benchmark deployments.
+# To share state across operators, swap in an S3 + DynamoDB backend block.

@@ -0,0 +1,75 @@
+resource "aws_vpc" "this" {
+  cidr_block           = var.vpc_cidr
+  enable_dns_hostnames = true
+  enable_dns_support   = true
+
+  tags = merge(var.tags, {
+    Name = "${var.name}-vpc"
+  })
+}
+
+resource "aws_internet_gateway" "this" {
+  vpc_id = aws_vpc.this.id
+
+  tags = merge(var.tags, {
+    Name = "${var.name}-igw"
+  })
+}
+
+resource "aws_subnet" "public" {
+  vpc_id                  = aws_vpc.this.id
+  cidr_block              = var.subnet_cidr
+  availability_zone       = var.availability_zone
+  map_public_ip_on_launch = true
+
+  tags = merge(var.tags, {
+    Name = "${var.name}-public-${var.availability_zone}"
+  })
+}
+
+resource "aws_route_table" "public" {
+  vpc_id = aws_vpc.this.id
+
+  route {
+    cidr_block = "0.0.0.0/0"
+    gateway_id = aws_internet_gateway.this.id
+  }
+
+  tags = merge(var.tags, {
+    Name = "${var.name}-public-rt"
+  })
+}
+
+resource "aws_route_table_association" "public" {
+  subnet_id      = aws_subnet.public.id
+  route_table_id = aws_route_table.public.id
+}
+
+resource "aws_security_group" "ssh" {
+  name        = "${var.name}-ssh"
+  description = "Optional SSH ingress for benchmark instances; default-deny if no CIDRs supplied."
+  vpc_id      = aws_vpc.this.id
+
+  dynamic "ingress" {
+    for_each = length(var.ssh_ingress_cidrs) > 0 ? [1] : []
+    content {
+      description = "SSH from operator workstation"
+      from_port   = 22
+      to_port     = 22
+      protocol    = "tcp"
+      cidr_blocks = var.ssh_ingress_cidrs
+    }
+  }
+
+  egress {
+    description = "Allow all egress (Docker pulls, package installs, telemetry)."
+    from_port   = 0
+    to_port     = 0
+    protocol    = "-1"
+    cidr_blocks = ["0.0.0.0/0"]
+  }
+
+  tags = merge(var.tags, {
+    Name = "${var.name}-ssh"
+  })
+}

@@ -0,0 +1,14 @@
+output "vpc_id" {
+  description = "ID of the benchmark VPC."
+  value       = aws_vpc.this.id
+}
+
+output "subnet_id" {
+  description = "ID of the single public subnet."
+  value       = aws_subnet.public.id
+}
+
+output "ssh_security_group_id" {
+  description = "Security-group ID granting SSH ingress (only if ssh_ingress_cidrs is non-empty)."
+  value       = aws_security_group.ssh.id
+}

@@ -0,0 +1,38 @@
+variable "name" {
+  description = "Name prefix applied to every resource in this module."
+  type        = string
+}
+
+variable "region" {
+  description = "AWS region for the benchmark deployment. Single region by D-002."
+  type        = string
+}
+
+variable "availability_zone" {
+  description = "Single AZ for all instances. Single-AZ on purpose (D-002) so latency numbers aren't muddied by cross-AZ hops."
+  type        = string
+}
+
+variable "vpc_cidr" {
+  description = "CIDR for the benchmark VPC."
+  type        = string
+  default     = "10.42.0.0/16"
+}
+
+variable "subnet_cidr" {
+  description = "CIDR for the single public subnet that hosts the benchmark EC2 instances."
+  type        = string
+  default     = "10.42.1.0/24"
+}
+
+variable "ssh_ingress_cidrs" {
+  description = "CIDRs allowed to SSH (port 22) into the benchmark instances. Default is empty — set explicitly to your /32 before applying."
+  type        = list(string)
+  default     = []
+}
+
+variable "tags" {
+  description = "Tags applied to every resource."
+  type        = map(string)
+  default     = {}
+}

@@ -0,0 +1,9 @@
+terraform {
+  required_version = ">= 1.6.0"
+  required_providers {
+    aws = {
+      source  = "hashicorp/aws"
+      version = ">= 5.40.0"
+    }
+  }
+}

@@ -0,0 +1,19 @@
+output "instance_id" {
+  description = "EC2 instance ID running pgvector."
+  value       = aws_instance.this.id
+}
+
+output "private_ip" {
+  description = "Private IP — use this from another instance in the same VPC. Connection string: postgresql://postgres:<password>@<private_ip>:5432/bench"
+  value       = aws_instance.this.private_ip
+}
+
+output "public_ip" {
+  description = "Public IP — used by the operator for SSH. Service port is NOT exposed publicly (security group is VPC-internal only)."
+  value       = aws_instance.this.public_ip
+}
+
+output "data_volume_id" {
+  description = "EBS volume ID backing /var/lib/postgresql."
+  value       = aws_ebs_volume.data.id
+}

